require "ui.GUIInvitationFriendItem"
local UIFriendInvitation = class("UIFriendInvitation", IGUILayout)


function UIFriendInvitation:onLoad()
    print("UIFriendInvitation:onLoad()")
    self:onLoadInitUI()

end

function UIFriendInvitation:onLoadInitUI()
    self.closeBtn = self:getChildWindow("SkyBlockFriendInvitation-Close", GUIType.Button)
    self.closeBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onClickClose()
    end)
    self.invitationLayout = self:getChildWindow("SkyBlockFriendInvitation-List", GUIType.Layout)
    self.invitationGridView = IGUIListView.new("sky_block-invitation-view", self.invitationLayout)
end

function UIFriendInvitation:onUpdateUserFriendInvitation()
    local filterData = self:filterApplyData(MultiBuildData.MyFriendData)
    local curData = GUIFriend:getSortData(filterData)
    self.invitationGridView:clearItems()
    for i, data in pairs(curData) do
        local curItem = UIFriendInvitationItem.new("SkyBlockInvitationFriendItem.json")
        curItem.root:SetArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 0, 92 })
        curItem:setItemData(data)
        self.invitationGridView:addItem(curItem)
    end
end

function UIFriendInvitation:isMainLayout()
    return false
end

function UIFriendInvitation:onClickClose()
    self:hide()
end

function UIFriendInvitation:filterApplyData(data)
    local cur_data = {}
    for k, v in pairs(data) do
        if v.isPlayCurGame == 1 and MultiBuildData:checkIsBuildMember(v.userId) == false and MultiBuildData.checkIsSendApply(v.userId) == false then
            --if MultiBuildData:checkIsBuildMember(v.userId) == false and MultiBuildData.checkIsSendApply(v.userId) == false then
            table.insert(cur_data, v)
        end
    end
    return cur_data
end

